import {
	ElMessage,
	ElMessageBox,
	ElNotification
} from 'element-plus'
import menu from './menu'
import CryptoJS from './cryptojs.js'

let KEY = '1234567890123456'
let IV = 'abcdefghijklmnop'

const requestCache = new Map()
const CACHE_DURATION = 5 * 60 * 1000

const toolUtil = {
	message(msg, type = 'info', close = null) {
		ElMessage({
			message: msg,
			type: type,
			duration: 2500,
			showClose: true,
			onClose() {
				if (close) {
					close()
				}
			}
		})
	},

	notify(title, msg, type = 'success', close = null) {
		ElNotification({
			title: title,
			message: msg,
			type: type,
			duration: 3000,
			onClose() {
				if (close) {
					close()
				}
			}
		})
	},

	confirm(message, title = '提示', type = 'warning') {
		return ElMessageBox.confirm(message, title, {
			confirmButtonText: '确定',
			cancelButtonText: '取消',
			type: type
		})
	},

	storageSet(key, value, duration = null) {
		try {
			const data = {
				value,
				timestamp: Date.now()
			}
			if (duration) {
				data.expire = Date.now() + duration
			}
			localStorage.setItem(key, JSON.stringify(data))
		} catch (error) {
			console.error('存储失败:', error)
		}
	},

	storageGet(key) {
		try {
			const item = localStorage.getItem(key)
			if (!item) return ""

			const data = JSON.parse(item)
			if (data.expire && Date.now() > data.expire) {
				localStorage.removeItem(key)
				return ""
			}
			return data.value
		} catch (error) {
			return localStorage.getItem(key) || ""
		}
	},

	storageGetObj(key) {
		try {
			const item = localStorage.getItem(key)
			if (!item) return null

			const data = JSON.parse(item)
			if (data.expire && Date.now() > data.expire) {
				localStorage.removeItem(key)
				return null
			}
			return data.value
		} catch (error) {
			try {
				return localStorage.getItem(key) ? JSON.parse(localStorage.getItem(key)) : null
			} catch {
				return null
			}
		}
	},

	storageRemove(key) {
		try {
			localStorage.removeItem(key)
		} catch (error) {
			console.error('删除失败:', error)
		}
	},

	storageClear() {
		try {
			localStorage.removeItem('Token')
			localStorage.removeItem('role')
			localStorage.removeItem('sessionTable')
			localStorage.removeItem('adminName')
		} catch (error) {
			console.error('清空失败:', error)
		}
	},

	setCache(key, value, duration = CACHE_DURATION) {
		try {
			const data = {
				value,
				timestamp: Date.now(),
				expire: Date.now() + duration
			}
			requestCache.set(key, data)
		} catch (error) {
			console.error('缓存失败:', error)
		}
	},

	getCache(key) {
		try {
			const data = requestCache.get(key)
			if (!data) return null

			if (Date.now() > data.expire) {
				requestCache.delete(key)
				return null
			}
			return data.value
		} catch (error) {
			console.error('读取缓存失败:', error)
			return null
		}
	},

	clearCache() {
		requestCache.clear()
	},

	isEmail(s) {
		return /^[a-zA-Z0-9_-]+@[a-zA-Z0-9_-]+\.[a-zA-Z0-9_-]{2,3}$/.test(s)
	},

	isMobile(s) {
		return /^(0|86|17951)?(13[0-9]|15[012356789]|16[6]|19[89]|17[01345678]|18[0-9]|14[579])[0-9]{8}$/.test(s)
	},

	isPhone(s) {
		return /^([0-9]{3,4}-)?[0-9]{7,8}$/.test(s)
	},

	isURL(s) {
		return /^https?:\/\/.+/.test(s)
	},

	isNumber(s) {
		return /(^-?[+-]?([0-9]*\.?[0-9]+|[0-9]+\.?[0-9]*)([eE][+-]?[0-9]+)?$)|(^$)/.test(s)
	},

	isIntNumer(s) {
		return /(^-?\d+$)|(^$)/.test(s)
	},

	checkIdCard(idcard) {
		if (!idcard) return false
		const regIdCard = /(^\d{15}$)|(^\d{18}$)|(^\d{17}(\d|X|x)$)/
		return regIdCard.test(idcard)
	},

	isAuth(tableName, key) {
		try {
			let role = toolUtil.storageGet("role")
			if (!role) {
				role = '管理员'
			}

			let menus = menu.list()
			if (!menus || !menus.length) return false

			for (let i = 0; i < menus.length; i++) {
				if (menus[i].roleName === role) {
					if (menus[i].backMenu && menus[i].backMenu.length) {
						for (let j = 0; j < menus[i].backMenu.length; j++) {
							if (menus[i].backMenu[j].child && menus[i].backMenu[j].child.length) {
								for (let k = 0; k < menus[i].backMenu[j].child.length; k++) {
									const tableParts = tableName.split('/')
									if (tableParts.length > 1) {
										if (tableParts[0] === menus[i].backMenu[j].child[k].tableName && 
											tableParts[1] === menus[i].backMenu[j].child[k].menuJump) {
											let buttons = menus[i].backMenu[j].child[k].buttons
											return buttons && buttons.indexOf(key) !== -1
										}
									} else {
										if (tableName === 'orders' && 
											menus[i].backMenu[j].child[k].tableName === 'orders' && 
											!menus[i].backMenu[j].child[k].menuJump) {
											let buttons = menus[i].backMenu[j].child[k].buttons
											return buttons && buttons.indexOf(key) !== -1
										}
										if (tableName !== 'orders' && 
											tableName === menus[i].backMenu[j].child[k].tableName) {
											let buttons = menus[i].backMenu[j].child[k].buttons
											return buttons && buttons.indexOf(key) !== -1
										}
									}
								}
							}
						}
					}
				}
			}
			return false
		} catch (error) {
			console.error('权限检查失败:', error)
			return false
		}
	},

	getCurDateTime() {
		let currentTime = new Date(),
			year = currentTime.getFullYear(),
			month = currentTime.getMonth() + 1 < 10 ? '0' + (currentTime.getMonth() + 1) : currentTime.getMonth() + 1,
			day = currentTime.getDate() < 10 ? '0' + currentTime.getDate() : currentTime.getDate(),
			hour = currentTime.getHours() < 10 ? '0' + currentTime.getHours() : currentTime.getHours(),
			minute = currentTime.getMinutes() < 10 ? '0' + currentTime.getMinutes() : currentTime.getMinutes(),
			second = currentTime.getSeconds() < 10 ? '0' + currentTime.getSeconds() : currentTime.getSeconds()
		return year + "-" + month + "-" + day + " " + hour + ":" + minute + ":" + second
	},

	getCurDate() {
		let currentTime = new Date(),
			year = currentTime.getFullYear(),
			month = currentTime.getMonth() + 1 < 10 ? '0' + (currentTime.getMonth() + 1) : currentTime.getMonth() + 1,
			day = currentTime.getDate() < 10 ? '0' + currentTime.getDate() : currentTime.getDate()
		return year + "-" + month + "-" + day
	},

	encryptDes(message) {
		try {
			const keyHex = CryptoJS.enc.Utf8.parse(KEY)
			const encrypted = CryptoJS.DES.encrypt(message, keyHex, {
				mode: CryptoJS.mode.ECB,
				padding: CryptoJS.pad.Pkcs7
			})
			return encrypted.toString()
		} catch (error) {
			console.error('DES加密失败:', error)
			return message
		}
	},

	decryptDes(ciphertext) {
		try {
			const keyHex = CryptoJS.enc.Utf8.parse(KEY)
			const decrypted = CryptoJS.DES.decrypt({
				ciphertext: CryptoJS.enc.Base64.parse(ciphertext)
			}, keyHex, {
				mode: CryptoJS.mode.ECB,
				padding: CryptoJS.pad.Pkcs7
			})
			return decrypted.toString(CryptoJS.enc.Utf8)
		} catch (error) {
			console.error('DES解密失败:', error)
			return ciphertext
		}
	},

	encryptAes(msg) {
		try {
			let cmode = CryptoJS.mode.CBC
			let cpad = CryptoJS.pad.Pkcs7
			let ciphertext = CryptoJS.AES.encrypt(msg, CryptoJS.enc.Utf8.parse(KEY), {
				mode: cmode,
				padding: cpad,
				iv: CryptoJS.enc.Utf8.parse(IV)
			}).toString()
			return ciphertext
		} catch (error) {
			console.error('AES加密失败:', error)
			return msg
		}
	},

	decryptAes(msg) {
		try {
			let cmode = CryptoJS.mode.CBC
			let cpad = CryptoJS.pad.Pkcs7
			var bytes = CryptoJS.AES.decrypt(msg, CryptoJS.enc.Utf8.parse(KEY), {
				mode: cmode,
				padding: cpad,
				iv: CryptoJS.enc.Utf8.parse(IV)
			})
			var originText = bytes.toString(CryptoJS.enc.Utf8)
			return originText
		} catch (error) {
			console.error('AES解密失败:', error)
			return msg
		}
	},

	debounce(func, wait) {
		let timeout
		return function executedFunction(...args) {
			const later = () => {
				timeout = null
				func(...args)
			}
			clearTimeout(timeout)
			timeout = setTimeout(later, wait)
		}
	},

	throttle(func, limit) {
		let inThrottle
		return function(...args) {
			if (!inThrottle) {
				func.apply(this, args)
				inThrottle = true
				setTimeout(() => inThrottle = false, limit)
			}
		}
	},

	deepClone(obj) {
		if (obj === null || typeof obj !== 'object') return obj
		if (obj instanceof Date) return new Date(obj.getTime())
		if (obj instanceof Array) return obj.map(item => this.deepClone(item))

		const clone = Array.isArray(obj) ? [] : {}
		for (const key in obj) {
			if (obj.hasOwnProperty(key)) {
				clone[key] = this.deepClone(obj[key])
			}
		}
		return clone
	},

	isEmpty(value) {
		if (value === null || value === undefined) return true
		if (typeof value === 'string') return value.trim() === ''
		if (Array.isArray(value)) return value.length === 0
		if (typeof value === 'object') return Object.keys(value).length === 0
		return false
	},

	logError(error, context = '未知') {
		console.error(`[${context}] 错误:`, error)
		if (process.env.NODE_ENV === 'development') {
			ElMessage.error(`[${context}] ${error.message || error}`)
		}
	}
}

export default toolUtil
